import{_ as t,c as e,o as p,ag as d}from"./chunks/framework.KLbWPeN7.js";const o="/images/r3ppro.png",r="/images/r3p-immortalwrt-2.png",i="/images/r3p-immortalwrt-1.png",u=JSON.parse('{"title":"40 多元淘的小米路由器Pro，开箱刷机详细教程","description":"","frontmatter":{},"headers":[],"relativePath":"flash-tutorials/xiaomiR3P.md","filePath":"flash-tutorials/xiaomiR3P.md"}'),s={name:"flash-tutorials/xiaomiR3P.md"};function n(l,a,b,m,h,f){return p(),e("div",null,a[0]||(a[0]=[d('<h1 id="_40-多元淘的小米路由器pro-开箱刷机详细教程" tabindex="-1">40 多元淘的小米路由器Pro，开箱刷机详细教程 <a class="header-anchor" href="#_40-多元淘的小米路由器pro-开箱刷机详细教程" aria-label="Permalink to &quot;40 多元淘的小米路由器Pro，开箱刷机详细教程&quot;">​</a></h1><ul><li>小米路由器Pro（型号 R3P），2017年的旗舰级 Wi-Fi 5 路由器，凭借全金属机身和高配置曾广受欢迎，但在 2026 年技术已显落后. 不推荐当主路由，适合网络爱好者刷机折腾或作为备用设备。搭载联发科MT7621A 双核880MHz处理器，配备512MB DDR3大内存和256MB NAND 闪存， 硬件底子扎实，无线性能双频并发速率最高2533Mbps，45包邮到手开搞!</li></ul><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><ul><li>40多元的小米路由器Pro一台</li><li>准备一跟网线，一台windows系统电脑。</li><li>下载刷机工具包，固件我已经打包好了放在网盘里面，兄弟们自取！</li></ul><blockquote><p>📺 视频教程：<br><a href="https://youtu.be/GJoKp9sl9Rk" target="_blank" rel="noreferrer">点击观看 YouTube 视频教程</a></p></blockquote><p>小米R3刷机工具包：</p><p>仅需 ¥4.6元 <a href="/shop/mipro-r3p.html">👉 立即购买</a>（网盘发货，收集固件录制视频不易感谢支持！）</p><p><img src="'+o+`" alt="CasaOS界面"></p><h2 id="一、开启ssh" tabindex="-1">一、开启SSH <a class="header-anchor" href="#一、开启ssh" aria-label="Permalink to &quot;一、开启SSH&quot;">​</a></h2><ul><li><p>1、第一步登录后台192.168.31.1降级到开发版固件，然后打开小米ssh开启工具，点击一键开启ssh.bat按照视频步骤开启就可以了!</p><pre><code>   能备份固件就备份，不能就到ssh里面备份！
</code></pre></li><li><p>2、备份路由器固件</p><pre><code>   查看分区情况

   cat /proc/mtd

   插个u盘到路由器上，查看以下

   df -h

  我的显示u盘如下：

  /dev/sda2      29.3G   4.3M   29.3G   0% /extdisks/sda2
</code></pre></li></ul><p>备份全部分区数据（sda2是我的u盘根据你的修改）</p><p>dd if=/dev/mtd0 of=/extdisks/sda2/ALL.bin</p><p>dd if=/dev/mtd1 of=/extdisks/sda2/Bootloader.bin</p><p>dd if=/dev/mtd2 of=/extdisks/sda2/Config.bin</p><p>dd if=/dev/mtd3 of=/extdisks/sda2/Bdata.bin</p><p>dd if=/dev/mtd4 of=/extdisks/sda2/Factory.bin</p><p>dd if=/dev/mtd5 of=/extdisks/sda2/crash.bin</p><p>dd if=/dev/mtd6 of=/extdisks/sda2/crash_syslog.bin</p><p>dd if=/dev/mtd7 of=/extdisks/sda2/reserved0.bin</p><p>dd if=/dev/mtd8 of=/extdisks/sda2/kernel0.bin</p><p>dd if=/dev/mtd9 of=/extdisks/sda2/kernel1.bin</p><p>dd if=/dev/mtd10 of=/extdisks/sda2/rootfs0.bin</p><p>dd if=/dev/mtd11 of=/extdisks/sda2/rootfs1.bin</p><p>dd if=/dev/mtd12 of=/extdisks/sda2/overlay.bin</p><h2 id="二、刷入pb-boot或者breed" tabindex="-1">二、刷入pb-boot或者breed <a class="header-anchor" href="#二、刷入pb-boot或者breed" aria-label="Permalink to &quot;二、刷入pb-boot或者breed&quot;">​</a></h2><p>1、上传pb-boot到路由器的tmp目录输入下面的命令开刷：</p><p>cd /tmp</p><p>mtd -r write /tmp/pb-boot-r3p.img Bootloader</p><p>刷入后，机器会重新启动，重启完后路由器亮黄灯，到此pb-boot刷入成功。</p><p>然后拔掉电源，用硬物顶住路由的reset键然后在插入电源开机，</p><p>等到路由的黄灯闪烁的时候，松开reset键，</p><p>在电脑上浏览器中输入192.168.1.1，就进入pb-boot控制台了。</p><p>2、刷入breed</p><p>mtd -r write /tmp/breed-mt7621-xiaomi-r3g-r3p.bin Bootloader</p><p>breed我没刷恩山说镁光芯片容易变砖，还有说NAND FLASH有坏块也会变砖，刷机有风险，变砖自己承担！</p><h2 id="三、padavan固件和openwrt固件" tabindex="-1">三、Padavan固件和OpenWrt固件 <a class="header-anchor" href="#三、padavan固件和openwrt固件" aria-label="Permalink to &quot;三、Padavan固件和OpenWrt固件&quot;">​</a></h2><p>1、刷Padavan</p><p>在电脑上浏览器中输入192.168.1.1，就进入pb-boot控制台，选择下载的Padavan固件包，点击恢复固件，开始刷机。</p><p>padavan</p><p>192.168.2.1</p><p>管理界面账户/密码：admin/admin</p><p>2、刷入OpenWrt</p><p>一定不要直接刷入openwert固件，可能变砖，先x-wrt过渡包在升级openwrt</p><p>在pb-boot中先刷入一个x-wrt固件过度，这是临时固件，无法保存任何设置，不能使用，记住了，刷完x-wrt后，浏览器登陆后台</p><p>192.168.15.1，密码：admin</p><p>在web界面中“系统-备份/升级中选择open-wrt (sysupgrade)固件升级，不保留配置！”即可平稳过度到openwrt固件</p><p>登陆web界面后记得接上wan口网线。</p><p>x-wrt</p><p>固件无线默认名称：X-WRT_XXXX，密码：88888888</p><p>固件管理界面：<a href="http://192.168.15.1/" target="_blank" rel="noreferrer">http://192.168.15.1/</a></p><p>管理界面账户/密码：admin/admin</p><p>SSH登录账户/密码：root/admin</p><p>kwrt</p><p>后台: 10.0.0.1 或 kwrt/ 密码: root</p><p><img src="`+r+'" alt="CasaOS界面"></p><h2 id="四、刷回原厂" tabindex="-1">四、刷回原厂 <a class="header-anchor" href="#四、刷回原厂" aria-label="Permalink to &quot;四、刷回原厂&quot;">​</a></h2><p>1、下载R3P开发版及ssh开启包，准备putty ssh工具 2、路由器断电，按住reset加电3秒黄灯闪所，浏览器192.168.1.1进入pb-boot界面，刷入开发版固件 3、开发版固件改名为miwifi.bin并复制到U盘，路由断电，按住reset不松开，路由加电等待刷入开发版 4、删除U盘开发版，并把ssh开启包和uboot（如果是用刷机工具备份的，在刷机工具下的data文件夹，mtd1.bin）复制到U盘，同3方式开启ssh 5、路由开发版固件启动，通过wifi连接并设置路由密码 6、ssh（192.168.31.1）进入路由，使用如下命令刷入uboot，即可完成回厂 mtd write /extdisks/sda1/mtd1.bin Bootloader</p><ul><li>收集整理不容易！记得视频点赞关注就是对我最大的支持！</li></ul><p><img src="'+i+'" alt="CasaOS界面"></p>',59)]))}const x=t(s,[["render",n]]);export{u as __pageData,x as default};
